1	import {
2	  ImageModelV3,
3	  ImageModelV3File,
4	  SharedV3Warning,
5	} from '@ai-sdk/provider';
6	import {
7	  FetchFunction,
8	  Resolvable,
9	  combineHeaders,
10	  convertUint8ArrayToBase64,
11	  createJsonErrorResponseHandler,
12	  createJsonResponseHandler,
13	  postJsonToApi,
14	  resolve,
15	} from '@ai-sdk/provider-utils';
16	import {
17	  BedrockImageModelId,
18	  modelMaxImagesPerCall,
19	} from './bedrock-image-settings';
20	import { BedrockErrorSchema } from './bedrock-error';
21	import { z } from 'zod/v4';
22	
23	type BedrockImageModelConfig = {
24	  baseUrl: () => string;
25	  headers: Resolvable<Record<string, string | undefined>>;
26	  fetch?: FetchFunction;
27	  _internal?: {
28	    currentDate?: () => Date;
29	  };
30	};
31	
32	export class BedrockImageModel implements ImageModelV3 {
33	  readonly specificationVersion = 'v3';
34	  readonly provider = 'amazon-bedrock';
35	
36	  get maxImagesPerCall(): number {
37	    return modelMaxImagesPerCall[this.modelId] ?? 1;
38	  }
39	
40	  private getUrl(modelId: string): string {
41	    const encodedModelId = encodeURIComponent(modelId);
42	    return `${this.config.baseUrl()}/model/${encodedModelId}/invoke`;
43	  }
44	
45	  constructor(
46	    readonly modelId: BedrockImageModelId,
47	    private readonly config: BedrockImageModelConfig,
48	  ) {}
49	
50	  async doGenerate({
51	    prompt,
52	    n,
53	    size,
54	    aspectRatio,
55	    seed,
56	    providerOptions,
57	    headers,
58	    abortSignal,
59	    files,
60	    mask,
61	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
62	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
63	  > {
64	    const warnings: Array<SharedV3Warning> = [];
65	    const [width, height] = size ? size.split('x').map(Number) : [];
66	
67	    const hasFiles = files != null && files.length > 0;
68	
69	    // Build image generation config (common to most modes)
70	    const imageGenerationConfig = {
71	      ...(width ? { width } : {}),
72	      ...(height ? { height } : {}),
73	      ...(seed ? { seed } : {}),
74	      ...(n ? { numberOfImages: n } : {}),
75	      ...(providerOptions?.bedrock?.quality
76	        ? { quality: providerOptions.bedrock.quality }
77	        : {}),
78	      ...(providerOptions?.bedrock?.cfgScale
79	        ? { cfgScale: providerOptions.bedrock.cfgScale }
80	        : {}),
81	    };
82	
83	    let args: Record<string, unknown>;
84	
85	    if (hasFiles) {
86	      // Check if mask is actually provided (has valid data, not just an empty object)
87	      const hasMask = mask?.type != null;
88	      const hasMaskPrompt = providerOptions?.bedrock?.maskPrompt != null;
89	
90	      // Determine task type from provider options, or infer from mask presence
91	      const taskType =
92	        providerOptions?.bedrock?.taskType ??
93	        (hasMask || hasMaskPrompt ? 'INPAINTING' : 'IMAGE_VARIATION');
94	
95	      const sourceImageBase64 = getBase64Data(files[0]);
96	
97	      switch (taskType) {
98	        case 'INPAINTING': {
99	          const inPaintingParams: Record<string, unknown> = {
100	            image: sourceImageBase64,
101	            ...(prompt ? { text: prompt } : {}),
102	            ...(providerOptions?.bedrock?.negativeText
103	              ? { negativeText: providerOptions.bedrock.negativeText }
104	              : {}),
105	          };
106	
107	          // Handle mask - can be either a maskImage or maskPrompt
108	          if (hasMask) {
109	            inPaintingParams.maskImage = getBase64Data(mask);
110	          } else if (hasMaskPrompt) {
111	            inPaintingParams.maskPrompt = providerOptions.bedrock.maskPrompt;
112	          }
113	
114	          args = {
115	            taskType: 'INPAINTING',
116	            inPaintingParams,
117	            imageGenerationConfig,
118	          };
119	          break;
120	        }
121	
122	        case 'OUTPAINTING': {
123	          const outPaintingParams: Record<string, unknown> = {
124	            image: sourceImageBase64,
125	            ...(prompt ? { text: prompt } : {}),
126	            ...(providerOptions?.bedrock?.negativeText
127	              ? { negativeText: providerOptions.bedrock.negativeText }
128	              : {}),
129	            ...(providerOptions?.bedrock?.outPaintingMode
130	              ? { outPaintingMode: providerOptions.bedrock.outPaintingMode }
131	              : {}),
132	          };
133	
134	          // Outpainting requires a maskImage (white pixels = area to change)
135	          if (hasMask) {
136	            outPaintingParams.maskImage = getBase64Data(mask);
137	          } else if (hasMaskPrompt) {
138	            outPaintingParams.maskPrompt = providerOptions.bedrock.maskPrompt;
139	          }
140	
141	          args = {
142	            taskType: 'OUTPAINTING',
143	            outPaintingParams,
144	            imageGenerationConfig,
145	          };
146	          break;
147	        }
148	
149	        case 'BACKGROUND_REMOVAL': {
150	          // Background removal only needs the image, no other params
151	          args = {
152	            taskType: 'BACKGROUND_REMOVAL',
153	            backgroundRemovalParams: {
154	              image: sourceImageBase64,
155	            },
156	          };
157	          break;
158	        }
159	
160	        case 'IMAGE_VARIATION': {
161	          // Image variation can use multiple images
162	          const images = files.map(file => getBase64Data(file));
163	
164	          const imageVariationParams: Record<string, unknown> = {
165	            images,
166	            ...(prompt ? { text: prompt } : {}),
167	            ...(providerOptions?.bedrock?.negativeText
168	              ? { negativeText: providerOptions.bedrock.negativeText }
169	              : {}),
170	            ...(providerOptions?.bedrock?.similarityStrength != null
171	              ? {
172	                  similarityStrength:
173	                    providerOptions.bedrock.similarityStrength,
174	                }
175	              : {}),
176	          };
177	
178	          args = {
179	            taskType: 'IMAGE_VARIATION',
180	            imageVariationParams,
181	            imageGenerationConfig,
182	          };
183	          break;
184	        }
185	
186	        default:
187	          throw new Error(`Unsupported task type: ${taskType}`);
188	      }
189	    } else {
190	      // Standard image generation mode
191	      args = {
192	        taskType: 'TEXT_IMAGE',
193	        textToImageParams: {
194	          text: prompt,
195	          ...(providerOptions?.bedrock?.negativeText
196	            ? {
197	                negativeText: providerOptions.bedrock.negativeText,
198	              }
199	            : {}),
200	          ...(providerOptions?.bedrock?.style
201	            ? {
202	                style: providerOptions.bedrock.style,
203	              }
204	            : {}),
205	        },
206	        imageGenerationConfig,
207	      };
208	    }
209	
210	    if (aspectRatio != undefined) {
211	      warnings.push({
212	        type: 'unsupported',
213	        feature: 'aspectRatio',
214	        details:
215	          'This model does not support aspect ratio. Use `size` instead.',
216	      });
217	    }
218	
219	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
220	    const { value: response, responseHeaders } = await postJsonToApi({
221	      url: this.getUrl(this.modelId),
222	      headers: await resolve(
223	        combineHeaders(await resolve(this.config.headers), headers),
224	      ),
225	      body: args,
226	      failedResponseHandler: createJsonErrorResponseHandler({
227	        errorSchema: BedrockErrorSchema,
228	        errorToMessage: error => `${error.type}: ${error.message}`,
229	      }),
230	      successfulResponseHandler: createJsonResponseHandler(
231	        bedrockImageResponseSchema,
232	      ),
233	      abortSignal,
234	      fetch: this.config.fetch,
235	    });
236	
237	    // Handle moderated/blocked requests
238	    if (response.status === 'Request Moderated') {
239	      const moderationReasons = response.details?.['Moderation Reasons'];
240	      const reasons = Array.isArray(moderationReasons)
241	        ? moderationReasons
242	        : ['Unknown'];
243	      throw new Error(
244	        `Amazon Bedrock request was moderated: ${reasons.join(', ')}`,
245	      );
246	    }
247	
248	    // Check if images are present
249	    if (!response.images || response.images.length === 0) {
250	      throw new Error(
251	        'Amazon Bedrock returned no images. ' +
252	          (response.status ? `Status: ${response.status}` : ''),
253	      );
254	    }
255	
256	    return {
257	      images: response.images,
258	      warnings,
259	      response: {
260	        timestamp: currentDate,
261	        modelId: this.modelId,
262	        headers: responseHeaders,
263	      },
264	    };
265	  }
266	}
267	
268	function getBase64Data(file: ImageModelV3File): string {
269	  if (file.type === 'url') {
270	    throw new Error(
271	      'URL-based images are not supported for Amazon Bedrock image editing. ' +
272	        'Please provide the image data directly.',
273	    );
274	  }
275	
276	  if (file.data instanceof Uint8Array) {
277	    return convertUint8ArrayToBase64(file.data);
278	  }
279	
280	  // Already base64 string
281	  return file.data;
282	}
283	
284	// minimal version of the schema, focussed on what is needed for the implementation
285	// this approach limits breakages when the API changes and increases efficiency
286	const bedrockImageResponseSchema = z.object({
287	  // Normal successful response
288	  images: z.array(z.string()).optional(),
289	
290	  // Moderation response fields
291	  id: z.string().optional(),
292	  status: z.string().optional(),
293	  result: z.unknown().optional(),
294	  progress: z.unknown().optional(),
295	  details: z.record(z.string(), z.unknown()).optional(),
296	  preview: z.unknown().optional(),
297	});
