270	class DefaultGenerateImageResult implements GenerateImageResult {
271	  readonly images: Array<GeneratedFile>;
272	  readonly warnings: Array<Warning>;
273	  readonly responses: Array<ImageModelResponseMetadata>;
274	  readonly providerMetadata: ImageModelV3ProviderMetadata;
275	  readonly usage: ImageModelUsage;
276	
277	  constructor(options: {
278	    images: Array<GeneratedFile>;
279	    warnings: Array<Warning>;
280	    responses: Array<ImageModelResponseMetadata>;
281	    providerMetadata: ImageModelV3ProviderMetadata;
282	    usage: ImageModelUsage;
283	  }) {
284	    this.images = options.images;
285	    this.warnings = options.warnings;
286	    this.responses = options.responses;
287	    this.providerMetadata = options.providerMetadata;
288	    this.usage = options.usage;
