      url: `${this.config.baseURL}/${this.modelId}`,
      body: requestBody
    });

    // Download images from URLs
    const downloadedImages = await Promise.all(
      targetImages.map(image => this.downloadImage(image.url))
    );

    return {
      images: downloadedImages,
      providerMetadata: {
        fal: {
          images: targetImages.map((image, index) => ({
            nsfw: has_nsfw_concepts?.[index]
            // ... other metadata
          }))
        }
      }
    };
  }
}
```

### 6. **Usage Flow: `generateImage()` Function**

**Location:** `/packages/ai/src/generate-image/generate-image.ts`

The high-level API that orchestrates everything:

```typescript
export async function generateImage({
  model,           // ImageModel (string or ImageModelV3)
  prompt,          // GenerateImagePrompt (string or with images/mask)
  n = 1,           // Number of images
  size,            // "1024x1024"
  aspectRatio,     // "16:9"
  seed,            // Optional seed
  providerOptions, // Provider-specific settings
  maxRetries = 2,
  abortSignal,
  headers
}): Promise<GenerateImageResult> {
  const model = resolveImageModel(modelArg);

  // Determine max images per call (can be async function)
  const maxImagesPerCallWithDefault = 
    maxImagesPerCall ?? (await invokeModelMaxImagesPerCall(model)) ?? 1;

  // Parallelize multiple calls if n > maxImagesPerCall
  const callCount = Math.ceil(n / maxImagesPerCallWithDefault);
  const callImageCounts = Array.from({ length: callCount }, (_, i) => {
    if (i < callCount - 1) return maxImagesPerCallWithDefault;
    const remainder = n % maxImagesPerCallWithDefault;
    return remainder === 0 ? maxImagesPerCallWithDefault : remainder;
  });

  // Execute all calls in parallel with retries
  const results = await Promise.all(
    callImageCounts.map(callImageCount =>
      retry(() => 
        model.doGenerate({
          prompt: normalizePrompt(promptArg).prompt,
          files: normalizePrompt(promptArg).files,
          mask: normalizePrompt(promptArg).mask,
          n: callImageCount,
          size, aspectRatio, seed,
          providerOptions: providerOptions ?? {},
          abortSignal, headers
        })
      )
    )
  );

  // Aggregate results
  return {
    images: [...],
    warnings: [...],
    responses: [...],
    providerMetadata: {...},
    usage: {...}
  };
}
```

### 7. **Provider Utilities**

**Location:** `/packages/provider-utils/src/`

Key utilities for providers:

- **`convertImageModelFileToDataUri()`**: Converts `ImageModelV3File` to data URI or returns URL as-is
- **`postJsonToApi()` / `postFormDataToApi()`**: HTTP request helpers
- **`combineHeaders()`**: Merges provider and user headers
- **`createJsonResponseHandler()`**: Validates and parses JSON responses with Zod schemas

### 8. **Image Model v2 (Legacy)**

**Location:** `/packages/provider/src/image-model/v2/`

There's also a v2 interface for backward compatibility, but v3 is the current standard. The main differences:
- V2 uses `ImageModelV2CallWarning` (different warning structure)
- No `usage` field in v2 response
- Same core concept of `doGenerate()` method

### Key Takeaways:

1. **Interface Pattern**: Providers implement `ImageModelV3` with a `doGenerate()` method
2. **Settings Flow**: `providerOptions` keyed by provider name allows provider-specific parameters to flow through unchanged
3. **Parallel Calls**: `generateImage()` automatically handles requesting more images than `maxImagesPerCall` by making multiple API calls
4. **File Handling**: Supports both base64 strings and Uint8Array, with automatic detection of media types
5. **Flexibility**: `maxImagesPerCall` can be a function, allowing dynamic limits based on model ID
6. **Warnings**: Providers can report unsupported features (e.g., "aspectRatio not supported, use size instead")
7. **Provider Metadata**: Each provider can return provider-specific metadata alongside images

