## 3. PROVIDER FACTORY FUNCTION PATTERN: `openai-provider.ts`

The factory function is the core of each provider. Here's the OpenAI pattern:

```typescript
// Interfaces define provider capabilities
export interface OpenAIProvider extends ProviderV3 {
  (modelId: OpenAIResponsesModelId): LanguageModelV3;
  languageModel(modelId: OpenAIResponsesModelId): LanguageModelV3;
  chat(modelId: OpenAIChatModelId): LanguageModelV3;
  completion(modelId: OpenAICompletionModelId): LanguageModelV3;
  embedding(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
  image(modelId: OpenAIImageModelId): ImageModelV3;
  transcription(modelId: OpenAITranscriptionModelId): TranscriptionModelV3;
  speech(modelId: OpenAISpeechModelId): SpeechModelV3;
  tools: typeof openaiTools;
}

export interface OpenAIProviderSettings {
  baseURL?: string;
  apiKey?: string;
  organization?: string;
  project?: string;
  headers?: Record<string, string>;
  name?: string;
  fetch?: FetchFunction;
}

// Factory function creates provider instance
export function createOpenAI(
  options: OpenAIProviderSettings = {},
): OpenAIProvider {
  // Resolve config from options or environment
  const baseURL = withoutTrailingSlash(
    loadOptionalSetting({
      settingValue: options.baseURL,
      environmentVariableName: 'OPENAI_BASE_URL',
    }),
  ) ?? 'https://api.openai.com/v1';

  // Create auth headers
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'OPENAI_API_KEY',
          description: 'OpenAI',
        })}`,
        ...options.headers,
      },
      `ai-sdk/openai/${VERSION}`,
    );

  // Create model factories - each returns instantiated model class
  const createChatModel = (modelId: OpenAIChatModelId) =>
    new OpenAIChatLanguageModel(modelId, {
      provider: `${providerName}.chat`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // Return provider object with all model creation methods
  return {
    specificationVersion: 'v3' as const,
    languageModel: createChatModel,
    chat: createChatModel,
    completion: createCompletionModel,
    embedding: createEmbeddingModel,
    image: createImageModel,
    transcription: createTranscriptionModel,
    speech: createSpeechModel,
    tools: openaiTools,
  };
}

// Default singleton instance
export const openai = createOpenAI();
```

---

## 4. SIMPLER PROVIDER EXAMPLE: `packages/fal` (Image/Video Generation)

FAL is simpler—it focuses on image, video, speech, and transcription. No language models.

**Directory Structure:**
```
packages/fal/
├── src/
│   ├── fal-image-model.ts               # Image generation
│   ├── fal-image-options.ts
│   ├── fal-image-settings.ts
│   ├── fal-video-model.ts               # Video generation
│   ├── fal-video-settings.ts
│   ├── fal-speech-model.ts              # Text-to-speech
│   ├── fal-speech-settings.ts
│   ├── fal-transcription-model.ts       # Speech-to-text
│   ├── fal-transcription-options.ts
│   ├── fal-provider.ts                  # Factory
│   ├── fal-config.ts
│   ├── fal-error.ts
│   ├── fal-api-types.ts
│   ├── index.ts
│   ├── version.ts
│   ├── __fixtures__/                    # Test data
│   ├── __snapshots__/
│   └── [test files]
├── package.json (same structure as OpenAI)
├── tsconfig.json (same references pattern)
└── [build config files]
```

**FAL Index Exports:**
```typescript
export type { FalProvider, FalProviderSettings } from './fal-provider';
export { createFal, fal } from './fal-provider';
export type { FalImageModelOptions };
export type { FalSpeechModelOptions };
export type { FalTranscriptionModelOptions };
export type { FalVideoModelOptions };
export { VERSION };
```

**FAL Provider Factory:**
```typescript
export interface FalProvider extends ProviderV3 {
  image(modelId: FalImageModelId): ImageModelV3;
  imageModel(modelId: FalImageModelId): ImageModelV3;
  transcription(modelId: FalTranscriptionModelId): TranscriptionModelV3;
  video(modelId: FalVideoModelId): Experimental_VideoModelV3;
  videoModel(modelId: FalVideoModelId): Experimental_VideoModelV3;
  speech(modelId: FalSpeechModelId): SpeechModelV3;
}

export function createFal(options: FalProviderSettings = {}): FalProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Key ${loadFalApiKey({
          apiKey: options.apiKey,
        })}`,
        ...options.headers,
      },
      `ai-sdk/fal/${VERSION}`,
    );

  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // ... similar for video, speech, transcription

  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    speech: createSpeechModel,
    transcription: createTranscriptionModel,
    video: createVideoModel,
    videoModel: createVideoModel,
  };
}

export const fal = createFal();
```

---

## 5. ROOT `tsconfig.json` REFERENCES ARRAY

The root tsconfig.json uses monorepo project references pattern:

```json
{
  "references": [
    { "path": "packages/ai" },
    { "path": "packages/mcp" },
    { "path": "packages/alibaba" },
    { "path": "packages/amazon-bedrock" },
    { "path": "packages/angular" },
    { "path": "packages/anthropic" },
    // ... [full list of all 50+ packages]
    { "path": "packages/openai" },
    { "path": "packages/fal" },
    { "path": "packages/google" },
    // ... etc
  ],
  "include": []
}
```

---

## 6. CONTRIBUTING DOCS: `contributing/add-new-provider.md`

```markdown
# Add new provider

## @ai-sdk/<provider> vs 3rd party package
Every provider is welcome to create a 3rd party package. We are happy to link 
from documentation. If you prefer 1st party @ai-sdk/<provider>, create an issue first.

## Steps:
1. Create new folder `packages/<provider>`
2. Set version to `0.0.0` in package.json
3. Create changeset for new package with `major`
4. Add examples to `examples/ai-functions/src/*/<provider>.ts` 
   depending on model types supported
5. Add documentation in `content/providers/01-ai-sdk-providers/<number>-<provider>.mdx`

## Pre-release
If main publishes beta releases, no action needed. Don't backport to vX.Y 
stable branch to avoid npm version conflicts.
```

---

## 7. KEY ARCHITECTURAL PATTERNS

**Package.json Pattern:**
- All providers use same format: `@ai-sdk/<name>`
- Dependencies: `@ai-sdk/provider` (interfaces) + `@ai-sdk/provider-utils` (utilities)
- Peer dependency on `zod` for schema validation
- Export both default factory (`createX()`) and singleton (`X`)

**TypeScript Configuration:**
- All extend `@vercel/ai-tsconfig/ts-library.json` (shared base)
- Use `"composite": true` for monorepo references
- Always reference `../provider` and `../provider-utils`

**Provider Structure:**
- **ProviderV3 interface**: Extends base provider with v3 specification
- **Settings interface**: Configuration options (apiKey, baseURL, headers, fetch)
- **Factory function**: `createX(options)` returns provider instance
- **Model classes**: One per capability (LanguageModelV3, ImageModelV3, etc.)
- **Singleton instance**: Default export (e.g., `export const fal = createFal()`)

**Model Class Pattern:**
- Implements V3 specification interface (e.g., `ImageModelV3`)
- Constructor takes modelId + config
- `doGenerate()` method: Core implementation with API calls
- Uses provider-utils for: API calls, header management, response parsing

**Directory Organization:**
- Separate subdirectory per model capability
- Options file for each model type (e.g., `fal-image-options.ts`)
- Settings file for model IDs (e.g., `fal-image-settings.ts`)
- API implementation details in model file
- Tests colocated with source (`*.test.ts`)

---

## 8. FILE PATHS REFERENCE

**Root Configuration:**
- `/tsconfig.json` (references all packages)
- `/contributing/add-new-provider.md` (provider creation guide)
- `/contributing/provider-architecture.md` (architecture overview)
- `/contributing/packages.md` (package listing & descriptions)

**OpenAI Provider:**
- `/packages/openai/package.json`
- `/packages/openai/tsconfig.json`
- `/packages/openai/src/index.ts`
- `/packages/openai/src/openai-provider.ts`
- `/packages/openai/src/openai-config.ts`

**FAL Provider:**
- `/packages/fal/package.json`
- `/packages/fal/tsconfig.json`
- `/packages/fal/src/index.ts`
- `/packages/fal/src/fal-provider.ts`
- `/packages/fal/src/fal-image-model.ts`
- `/packages/fal/src/fal-video-model.ts`

