}
```

---

### Step 3 — `packages/pixelart/tsconfig.build.json`

Identical to `packages/fal/tsconfig.build.json`:

```json
{
  "extends": "./tsconfig.json",
  "compilerOptions": {
    "composite": false
  }
}
```

---

### Step 4 — `packages/pixelart/tsup.config.ts`

Identical to `packages/fal/tsup.config.ts`:

```ts
import { defineConfig } from 'tsup';

export default defineConfig([
  {
    entry: ['src/index.ts'],
    format: ['cjs', 'esm'],
    dts: true,
    sourcemap: true,
    define: {
      __PACKAGE_VERSION__: JSON.stringify(
        (await import('./package.json', { with: { type: 'json' } })).default.version,
      ),
    },
  },
]);
```

---

### Step 5 — `packages/pixelart/vitest.node.config.js` and `vitest.edge.config.js`

Identical to FAL's configs (just different `environment`):

```js
// vitest.node.config.js
import { defineConfig } from 'vite';
import packageJson from './package.json';

export default defineConfig({
  test: { environment: 'node', include: ['**/*.test.ts', '**/*.test.tsx'] },
  define: { __PACKAGE_VERSION__: JSON.stringify(packageJson.version) },
});

// vitest.edge.config.js — same but environment: 'edge-runtime'
```

---

### Step 6 — `packages/pixelart/src/version.ts`

Identical to FAL's version.ts:

```ts
declare const __PACKAGE_VERSION__: string | undefined;
export const VERSION: string =
  typeof __PACKAGE_VERSION__ !== 'undefined' ? __PACKAGE_VERSION__ : '0.0.0-test';
```

---

### Step 7 — `packages/pixelart/src/pixelart-image-settings.ts`

Defines the model ID union type. Includes a few representative fictional models plus the open-ended `string & {}` escape hatch:

```ts
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | (string & {});
```

---

### Step 8 — `packages/pixelart/src/pixelart-image-options.ts`

Defines the provider-specific options schema (parsed from `providerOptions.pixelart`). Uses `zodSchema` + `lazySchema` from `@ai-sdk/provider-utils` and `zod/v4`, matching FAL's pattern:

```ts
import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The visual style of the generated pixel art.
       * - "pixel": Classic pixel art style
       * - "retro": Retro video game aesthetic
       * - "8bit": 8-bit era game graphics
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      /**
       * The pixel density of the output image (pixels per unit).
       * Higher values produce finer detail.
       */
      pixelDensity: z.number().min(1).max(64).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<typeof pixelArtImageModelOptionsSchema>;
```

---

### Step 9 — `packages/pixelart/src/pixelart-image-model.ts`

The core image model class implementing `ImageModelV3`. Key design:

- **Endpoint**: `POST https://api.pixelart.ai/v1/images/generate`
- **Request body**:
  ```json
  {
    "model": "<modelId>",
    "prompt": "...",
    "n": 1,
    "size": "512x512",
    "style": "pixel",
    "pixel_density": 8
  }
  ```
- **Unsupported features**: `aspectRatio` (adds a warning), `files`/`mask` (adds a warning — no editing support)
- **Response body** (Zod-validated):
  ```json
  { "created": 1234567890, "data": [{ "b64_json": "..." }] }
  ```
- Returns images as `string[]` (base64-encoded)
- Uses `postJsonToApi`, `combineHeaders`, `resolve`, `parseProviderOptions`, `createJsonResponseHandler`, `createJsonErrorResponseHandler` from `@ai-sdk/provider-utils`

```ts
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { pixelArtImageModelOptionsSchema } from './pixelart-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(options): Promise<...> {
    const warnings: SharedV3Warning[] = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // aspectRatio not supported — warn and ignore
    if (options.aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio. Use `size` instead.' });
    }

    // file editing not supported — warn and ignore
    if (options.files != null) {
      warnings.push({ type: 'unsupported', feature: 'image editing',
        details: 'PixelArt does not support image editing (files/mask).' });
    }

    // Parse provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions: options.providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt: options.prompt,
      n: options.n,
      size: options.size,
      seed: options.seed,
    };

    if (pixelArtOptions?.style != null) body.style = pixelArtOptions.style;
    if (pixelArtOptions?.pixelDensity != null) body.pixel_density = pixelArtOptions.pixelDensity;

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), options.headers),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelArtImageResponseSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: value.data.map(() => ({})),
          created: value.created,
        },
      },
    };
  }
}

// Response schema
const pixelArtImageResponseSchema = z.object({
  created: z.number(),
  data: z.array(z.object({ b64_json: z.string() })),
});

// Error schema
const pixelArtErrorSchema = z.object({ error: z.object({ message: z.string() }) });

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});
```

---

### Step 10 — `packages/pixelart/src/pixelart-provider.ts`

The provider factory. Only exposes `image`/`imageModel`; throws `NoSuchModelError` for `languageModel` and `embeddingModel`:

```ts
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import { FetchFunction, loadApiKey, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /** API key. Defaults to PIXELART_API_KEY env var. */
  apiKey?: string;
  /** Base URL. Defaults to https://api.pixelart.ai/v1 */
  baseURL?: string;
  /** Custom HTTP headers. */
  headers?: Record<string, string>;
  /** Custom fetch implementation. */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL)!;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

export const pixelArt = createPixelArt();
```

---

### Step 11 — `packages/pixelart/src/index.ts`

```ts
export type { PixelArtProvider, PixelArtProviderSettings } from './pixelart-provider';
export { createPixelArt, pixelArt } from './pixelart-provider';
export type { PixelArtImageModelOptions } from './pixelart-image-options';
export { VERSION } from './version';
```

---

### Step 12 — `packages/pixelart/src/pixelart-image-model.test.ts`

Tests using `createTestServer` from `@ai-sdk/test-server`. Cover:

1. **Basic generation** — verify request body (model, prompt, n, size, seed) and returned base64 images
2. **Provider options** — verify `style` maps to `style` and `pixelDensity` maps to `pixel_density` in request body
3. **Unsupported features** — verify `aspectRatio` produces a warning and is not sent in request body
4. **Unsupported files/mask** — verify a warning is added
5. **Error handling** — mock a 400 error response, verify it throws with the right message
6. **Headers** — verify Authorization header is set correctly from apiKey

Test structure follows FAL's pattern: `createTestServer`, then `describe`/`it` blocks asserting `server.calls[0].requestBodyJson` and checking returned `images`.

---

### Step 13 — Update root `tsconfig.json`

Add `{ "path": "packages/pixelart" }` in alphabetical order. It belongs between `packages/perplexity` (line 38) and `packages/provider` (line 41):

**Old:**
```json
    { "path": "packages/perplexity" },
    { "path": "packages/provider" },
```

**New:**
```json
    { "path": "packages/perplexity" },
    { "path": "packages/pixelart" },
    { "path": "packages/provider" },
```

---

## Utilities to Reuse (from `@ai-sdk/provider-utils`)

| Utility | Source | Used in |
|---|---|---|
| `loadApiKey` | `load-api-key.ts` | `pixelart-provider.ts` — load API key from env |
| `withoutTrailingSlash` | `without-trailing-slash.ts` | `pixelart-provider.ts` — normalize baseURL |
| `withUserAgentSuffix` | `with-user-agent-suffix.ts` | `pixelart-provider.ts` — set User-Agent header |
| `postJsonToApi` | `post-to-api.ts` | `pixelart-image-model.ts` — HTTP POST |
| `combineHeaders` | `combine-headers.ts` | `pixelart-image-model.ts` — merge headers |
| `resolve` | `resolve.ts` | `pixelart-image-model.ts` — resolve async headers |
| `parseProviderOptions` | `parse-provider-options.ts` | `pixelart-image-model.ts` — extract `providerOptions.pixelart` |
| `createJsonResponseHandler` | `response-handler.ts` | `pixelart-image-model.ts` — parse success response |
| `createJsonErrorResponseHandler` | `response-handler.ts` | `pixelart-image-model.ts` — parse error response |
| `lazySchema`, `zodSchema`, `InferSchema` | `schema.ts` | `pixelart-image-options.ts` — schema definition |
| `FetchFunction`, `Resolvable` | `types/` | type imports |

From `@ai-sdk/provider`:
- `ImageModelV3`, `NoSuchModelError`, `ProviderV3`, `SharedV3Warning`

From `@ai-sdk/test-server`:
- `createTestServer` — mock HTTP server for tests

---

## Verification

### Type checking
```bash
cd packages/pixelart && pnpm type-check
# or from root:
pnpm type-check:full
```

### Unit tests
```bash
cd packages/pixelart && pnpm test:node
cd packages/pixelart && pnpm test:edge
# or shorthand:
cd packages/pixelart && pnpm test
```

### Build
```bash
cd packages/pixelart && pnpm build
```

### Manual smoke test (after build, requires real or mocked API)
```ts
import { createPixelArt } from '@ai-sdk/pixelart';
import { generateImage } from 'ai';

const pixelArt = createPixelArt({ apiKey: 'test-key' });

const result = await generateImage({
  model: pixelArt.image('pixelart-v1'),
  prompt: 'A retro space invader',
  size: '512x512',
  providerOptions: {
    pixelart: { style: 'pixel', pixelDensity: 8 },
  },
});
```

