import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.pixelart.ai/v1';
const TEST_ENDPOINT = `${TEST_BASE_URL}/images/generate`;
const prompt = 'A retro space invader';

const mockSuccessResponse = {
  created: 1700000000,
  data: [{ b64_json: 'aGVsbG8=' }],
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [TEST_ENDPOINT]: {
      response: {
        type: 'json-value',
        body: mockSuccessResponse,
      },
    },
  });

  describe('doGenerate', () => {
    it('should send the correct basic request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '512x512',
      });
    });

    it('should include seed when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: 42,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '256x256',
        seed: 42,
      });
    });

    it('should omit size when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 2,
      });
      expect(body).not.toHaveProperty('size');
    });

    it('should send style and pixel_density from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: { style: 'retro', pixelDensity: 16 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '512x512',
        style: 'retro',
        pixel_density: 16,
      });
    });

    it('should support all three style values', async () => {
      const model = createBasicModel();

      for (const style of ['pixel', 'retro', '8bit'] as const) {
        await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          files: undefined,
          mask: undefined,
          providerOptions: { pixelart: { style } },
        });

        const body = await server.calls[server.calls.length - 1].requestBodyJson;
        expect(body).toMatchObject({ style });
      }
    });

    it('should not include style or pixel_density when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('should return base64-encoded images from response', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.images).toStrictEqual(['aGVsbG8=']);
    });

    it('should return multiple images when response contains multiple', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [{ b64_json: 'aW1hZ2Ux' }, { b64_json: 'aW1hZ2Uy' }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.images).toStrictEqual(['aW1hZ2Ux', 'aW1hZ2Uy']);

      // Restore default
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: mockSuccessResponse,
      };
    });

    it('should warn when aspectRatio is provided and not include it in request', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'aspectRatio',
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('aspectRatio');
      expect(body).not.toHaveProperty('aspect_ratio');
    });

    it('should warn when files are provided (image editing not supported)', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: [{ type: 'url', url: 'https://example.com/input.png' }],
        mask: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'image editing',
      });
    });

    it('should include correct response metadata', async () => {
      const fixedDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => fixedDate,
      });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.response).toMatchObject({
        modelId: 'pixelart-v1',
        timestamp: fixedDate,
      });
    });

    it('should include providerMetadata with created timestamp', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata).toMatchObject({
        pixelart: {
          created: 1700000000,
          images: [{}],
        },
      });
    });

    it('should set the Authorization header from the provider config', async () => {
      const model = createBasicModel({
        headers: { Authorization: 'Bearer my-api-key' },
      });

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer my-api-key',
      });
    });

    it('should throw an error on a failed API response', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: { error: { message: 'Invalid API key provided' } },
        status: 401,
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          files: undefined,
          mask: undefined,
          providerOptions: {},
        }),
      ).rejects.toThrow('Invalid API key provided');

      // Restore default
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: mockSuccessResponse,
      };
    });

    it('should have correct specificationVersion and modelId', () => {
      const model = createBasicModel();
      expect(model.specificationVersion).toBe('v3');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.provider).toBe('pixelart.image');
      expect(model.maxImagesPerCall).toBe(1);
    });
  });
});

