      const model = createBasicModel({
        currentDate: () => fixedDate,
      });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.response).toMatchObject({
        modelId: 'pixelart-v1',
        timestamp: fixedDate,
      });
    });

    it('should include providerMetadata with created timestamp', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
